import React, { useState } from "react";
import { useNavigate } from "react-router-dom";
import { Cpu, Shield, Code, Clock, Activity, AlertTriangle, FileSearch } from "lucide-react";

/*
AssignedSystems.jsx
Technician operational page
Future API:
GET /api/technician/assigned-systems
*/

const AssignedSystems = () => {

  const navigate = useNavigate();

  /* -----------------------------
     Dummy Backend Response
  ----------------------------- */

  const systemsData = [
    {
      systemId: "SYS-10234",
      owner: "Finance Dept",
      assignedDate: "2026-01-12",
      severity: "Critical",
      rootCause: "Disk I/O saturation",
      status: "In Progress",
      slaHours: -2,
      category: "Hardware",
    },
    {
      systemId: "SYS-10241",
      owner: "HR Systems",
      assignedDate: "2026-01-14",
      severity: "High",
      rootCause: "Authentication service failure",
      status: "Pending",
      slaHours: 5,
      category: "Security",
    },
    {
      systemId: "SYS-10258",
      owner: "Manufacturing",
      assignedDate: "2026-01-15",
      severity: "Medium",
      rootCause: "Memory leak in service",
      status: "Awaiting Evidence",
      slaHours: 18,
      category: "Software",
    },
  ];

  const [search, setSearch] = useState("");
  const [filter, setFilter] = useState("All");

  /* -----------------------------
     Navigation
  ----------------------------- */

  const openDiagnosis = (systemId) => {
    navigate(`/technician/diagnosis/${systemId}`);
  };

  /* -----------------------------
     Filtering
  ----------------------------- */

  const filteredSystems = systemsData.filter((sys) => {

    const matchesSearch =
      sys.systemId.toLowerCase().includes(search.toLowerCase()) ||
      sys.owner.toLowerCase().includes(search.toLowerCase());

    const matchesFilter =
      filter === "All" ||
      sys.severity === filter ||
      sys.status === filter;

    return matchesSearch && matchesFilter;
  });

  /* -----------------------------
     Snapshot Metrics
  ----------------------------- */

  const snapshot = {
    pending: systemsData.filter((s) => s.status === "Pending").length,
    inProgress: systemsData.filter((s) => s.status === "In Progress").length,
    breached: systemsData.filter((s) => s.slaHours < 0).length,
    awaiting: systemsData.filter((s) => s.status === "Awaiting Evidence").length,
  };

  /* -----------------------------
     UI Helpers
  ----------------------------- */

  const severityStyles = {
    Critical: "bg-red-100 text-red-700",
    High: "bg-orange-100 text-orange-700",
    Medium: "bg-yellow-100 text-yellow-700",
    Low: "bg-green-100 text-green-700",
  };

  const statusStyles = {
    Pending: "bg-gray-100 text-gray-700",
    "In Progress": "bg-blue-100 text-blue-700",
    "Awaiting Evidence": "bg-purple-100 text-purple-700",
  };

  const categoryIcons = {
    Hardware: <Cpu size={16} />,
    Software: <Code size={16} />,
    Security: <Shield size={16} />,
  };

  /* -----------------------------
     Render
  ----------------------------- */

  return (
    <div className="space-y-6">

      {/* HEADER */}

      <div className="flex flex-col lg:flex-row lg:items-center lg:justify-between gap-4">

        <div>
          <h1 className="text-2xl font-semibold text-gray-900">
            Assigned Systems
          </h1>
          <p className="text-sm text-gray-500">
            Systems assigned to you for investigation
          </p>
        </div>

        <div className="flex flex-col sm:flex-row gap-3">

          <input
            type="text"
            placeholder="Search system or owner"
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            className="border rounded-md px-3 py-2 text-sm focus:ring-2 focus:ring-blue-500"
          />

          <select
            value={filter}
            onChange={(e) => setFilter(e.target.value)}
            className="border rounded-md px-3 py-2 text-sm focus:ring-2 focus:ring-blue-500"
          >
            <option value="All">All</option>
            <option value="Critical">Critical</option>
            <option value="High">High</option>
            <option value="Medium">Medium</option>
            <option value="Pending">Pending</option>
            <option value="In Progress">In Progress</option>
            <option value="Awaiting Evidence">Awaiting Evidence</option>
          </select>

        </div>

      </div>

      {/* SNAPSHOT METRICS */}

      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">

        <SnapshotCard icon={<Clock size={18} />} label="Pending" value={snapshot.pending} />
        <SnapshotCard icon={<Activity size={18} />} label="In Progress" value={snapshot.inProgress} />
        <SnapshotCard icon={<AlertTriangle size={18} />} label="SLA Breached" value={snapshot.breached} danger />
        <SnapshotCard icon={<FileSearch size={18} />} label="Awaiting Evidence" value={snapshot.awaiting} />

      </div>

      {/* SYSTEMS TABLE */}

      <div className="bg-white border rounded-lg overflow-hidden">

        <div className="overflow-x-auto">

          <table className="min-w-[900px] w-full text-sm">

            <thead className="bg-gray-50 text-gray-600">

              <tr>
                <th className="px-4 py-3 text-left">System</th>
                <th className="px-4 py-3 text-left">Severity</th>
                <th className="px-4 py-3 text-left">Root Cause</th>
                <th className="px-4 py-3 text-left">Status</th>
                <th className="px-4 py-3 text-left">SLA</th>
                <th className="px-4 py-3 text-left">Action</th>
              </tr>

            </thead>

            <tbody>

              {filteredSystems.length === 0 && (
                <tr>
                  <td colSpan="6" className="text-center py-8 text-gray-500">
                    No systems match your filters
                  </td>
                </tr>
              )}

              {filteredSystems.map((sys) => (

                <tr key={sys.systemId} className="border-t hover:bg-gray-50">

                  {/* SYSTEM */}

                  <td
                    className="px-4 py-3 font-medium text-blue-600 cursor-pointer"
                    onClick={() => openDiagnosis(sys.systemId)}
                  >
                    <div>
                      <p>{sys.systemId}</p>
                      <p className="text-xs text-gray-500">{sys.owner}</p>
                    </div>
                  </td>

                  {/* SEVERITY */}

                  <td className="px-4 py-3">

                    <span
                      className={`px-2 py-1 rounded-full text-xs font-medium ${severityStyles[sys.severity]}`}
                    >
                      {sys.severity}
                    </span>

                  </td>

                  {/* ROOT CAUSE */}

                  <td className="px-4 py-3 flex items-center gap-2">

                    {categoryIcons[sys.category]}

                    {sys.rootCause}

                  </td>

                  {/* STATUS */}

                  <td className="px-4 py-3">

                    <span
                      className={`px-2 py-1 rounded-full text-xs font-medium ${statusStyles[sys.status]}`}
                    >
                      {sys.status}
                    </span>

                  </td>

                  {/* SLA */}

                  <td className="px-4 py-3">

                    <span
                      className={`font-medium ${
                        sys.slaHours < 0
                          ? "text-red-600"
                          : sys.slaHours < 6
                          ? "text-orange-600"
                          : "text-green-600"
                      }`}
                    >
                      {sys.slaHours < 0 ? "BREACHED" : `${sys.slaHours} hrs`}
                    </span>

                  </td>

                  {/* ACTION */}

                  <td className="px-4 py-3">

                    <button
                      onClick={() => openDiagnosis(sys.systemId)}
                      className="px-3 py-1.5 bg-blue-600 text-white rounded-md text-xs hover:bg-blue-700"
                    >
                      Investigate
                    </button>

                  </td>

                </tr>

              ))}

            </tbody>

          </table>

        </div>

      </div>

    </div>
  );
};

/* Snapshot Card */

const SnapshotCard = ({ icon, label, value, danger }) => (
  <div
    className={`border rounded-lg p-4 flex items-center justify-between ${
      danger ? "border-red-300 bg-red-50" : "bg-white"
    }`}
  >
    <div>
      <p className="text-sm text-gray-500">{label}</p>
      <p className={`text-2xl font-semibold ${danger ? "text-red-600" : "text-gray-900"}`}>
        {value}
      </p>
    </div>

    <div className="p-2 bg-gray-100 rounded">
      {icon}
    </div>
  </div>
);

export default AssignedSystems;
